files.rangeutil.py:
def inclusive_range(a, b):
    """Return the integers from a to b inclusive."""
    return list(range(a, b))

files.summer.py:
from rangeutil import inclusive_range


def sum_inclusive(a, b):
    return sum(inclusive_range(a, b + 1))


def list_inclusive(a, b):
    return inclusive_range(a, b)

